413	// Non-cached I/O bus (peripheral register access) external interface
414	// write_en and read_en are mutually exclusive. When read_en is asserted, the
415	// data will appear on read_data one cycle later.
416	interface io_bus_interface;
417	    logic write_en;
418	    logic read_en;
419	    defines::scalar_t address;
420	    defines::scalar_t write_data;
421	    defines::scalar_t read_data;
422	
423	    modport master(output write_en, read_en, address, write_data, input read_data);
424	    modport slave(input write_en, read_en, address, write_data, output read_data);
425	endinterface
